import{_ as e,o as t,c as a,ak as s}from"./chunks/framework.DXL0ymeD.js";const m=JSON.parse('{"title":"雨霖铃","description":"","frontmatter":{"title":"雨霖铃","date":"2021-07-29T10:29:08.000Z","tags":null},"headers":[],"relativePath":"Articles and Poems/雨霖铃.md","filePath":"Articles and Poems/雨霖铃.md"}'),_={name:"Articles and Poems/雨霖铃.md"};function r(o,p,n,c,d,i){return t(),a("div",null,[...p[0]||(p[0]=[s("<p>听过秋蝉低鸣</p><p>孤凄落寞</p><p>又独面长亭</p><p>渐隐暮色</p><p>唯新落的雨</p><p>落日中舞动着匿去</p><p>别筵喧嚣</p><p>仿佛置身世外</p><p>酒在手中</p><p>又怎舍得开怀</p><p>泪垂入杯中</p><p>混合</p><p>发酵</p><p>流出苦涩的香</p><p>舟人催行不止</p><p>目光相依</p><p>却只有无声泪相送</p><p>此后的距离</p><p>再也不止云雾的尽头了</p><p>可云雾哪有尽头呢</p><p>怪我多情</p><p>多情人自古爱伤愁</p><p>何况这悲寥浅秋</p><p>泪酒一饮而尽</p><p>昏昏睡去</p><p>但什么时候醒来呢</p><p>就在某个清晨吧</p><p>杨柳岸边</p><p>凄冷凌风</p><p>看残月犹挂</p><p>可纵使天气正好</p><p>满腹思绪</p><p>却又有何人可诉</p>",33)])])}const f=e(_,[["render",r]]);export{m as __pageData,f as default};
